    eg_hero_sub:      { tr: "Berkay Er ile Ableton özel ders al: 2019'dan beri süregelen müzikal birikim ve prodüksiyon deneyimiyle elektronik müzik üretimini sıfırdan profesyonel düzeye taşı. Kişiye özel müfredat, online uygulamalı dersler.", en: 'Take private Ableton lessons with Berkay Er: take electronic music production from zero to professional level with years of musical knowledge and production experience since 2019. Personalized curriculum, online hands-on lessons.' },
    eg_chip1:         { tr: '🎁 1 Saat Ücretsiz Deneme', en: '🎁 1 Hour Free Trial' },
    eg_chip2:         { tr: '500 GB Preset Paketi',    en: '500 GB Preset Pack' },
    eg_chip3:         { tr: '8 Modül · Tüm Seviyeler', en: '8 Modules · All Levels' },
    eg_banner_btn:    { tr: 'Rezervasyon Yap →',       en: 'Book Now →' },
    eg_lab_teaser:    { tr: '🎛️ Ableton Lab — Synthesizer, Beat Maker, Mixer ve Arrangement Builder ile dersleri interaktif olarak pekiştir', en: '🎛️ Ableton Lab — Reinforce lessons interactively with Synthesizer, Beat Maker, Mixer and Arrangement Builder' },
    eg_lab_btn:       { tr: "Lab'ı Aç →",             en: 'Open Lab →' },
    eg_training_h2:   { tr: 'Ableton Özel Ders & Prodüksiyon Eğitimi', en: 'Private Ableton Lessons & Production Education' },
    eg_training_sub:  { tr: 'Açık ve net aktarım',    en: 'Clear and direct teaching' },
    eg_training_desc: { tr: "Berkay Er, yıllarca biriktirdiği müzikal deneyimi ve teknik birikimi yeni nesil üreticilerle paylaşıyor. Ableton Live üzerinde elektronik müzik prodüksiyonunun inceliklerini — Melodic Techno'dan Techno'ya, ses tasarımından mixing'e — kendi özgün bakış açısıyla aktarıyor. Her ders tamamen kişiye özel planlanır; seviyene, hedeflerine ve tarzına göre şekillenir.", en: "Berkay Er shares years of accumulated musical experience and technical knowledge with the next generation of producers. He conveys the nuances of electronic music production on Ableton Live — from Melodic Techno to Techno, from sound design to mixing — through his own unique perspective. Every lesson is planned entirely personally; it takes shape according to your level, goals and style." },
    eg_feat1:         { tr: 'Ableton Live kullanımı & workflow', en: 'Ableton Live usage & workflow' },
    eg_feat2:         { tr: 'Loop ve sample tasarımı',          en: 'Loop and sample design' },
    eg_feat3:         { tr: 'Melodic Techno yapım teknikleri',   en: 'Melodic Techno production techniques' },
    eg_feat4:         { tr: 'Ses mimarisi & atmosfer',          en: 'Sound architecture & atmosphere' },
    eg_feat5:         { tr: 'Live Set kurgulama & sahne',       en: 'Live Set creation & stage' },
    eg_feat6:         { tr: 'Özgün tarz geliştirme',           en: 'Developing a unique style' },
    eg_feat7:         { tr: 'Ayrıca 1 saat ücretsiz deneme dersi imkanı', en: 'Plus: 1 hour free trial lesson opportunity' },
    eg_preset_desc:   { tr: "Eğitime özel 500 GB Preset Paketi ve özenle seçilmiş Serum Preset'leri her öğrenciye ücretsiz olarak veriliyor.", en: 'An exclusive 500 GB Preset Pack and hand-picked Serum Presets are given free to every student.' },
    eg_free_btn:      { tr: '▶ Ücretsiz Derse Başla',          en: '▶ Start Free Lesson' },
    eg_curriculum_h2: { tr: '// Ders İçeriği',                 en: '// Curriculum' },
    eg_curriculum_intro: { tr: 'Elektronik müzik prodüksiyonunu sıfırdan ya da mevcut seviyenden profesyonel düzeye taşıyan, uygulamalı ve kişiye özel Ableton özel ders müfredatı. 8 modül, tüm seviyeler.', en: 'A hands-on and personalized Ableton private lesson curriculum that takes electronic music production from zero or current level to professional. 8 modules, all levels.' },
