    eg_reserve_sub:   { tr: 'Erişim kodunla günlerini seç, takvimini oluştur', en: 'Choose your days with your access code, build your schedule' },
    eg_faq_h2:        { tr: '// Sık Sorulan Sorular',          en: '// Frequently Asked Questions' },
    eg_faq1_q:        { tr: 'Ableton özel ders ücreti ne kadar?', en: 'How much does a private Ableton lesson cost?' },
    eg_faq1_a:        { tr: 'Ders paketi ve süreye göre değişmekle birlikte, önce 1 saatlik ücretsiz deneme dersi yapılır. Deneme sonrası kişiye özel fiyatlandırma sunulur.', en: 'Pricing varies by lesson package and duration, but starts with a free 1-hour trial lesson. After the trial, personalized pricing is offered.' },
    eg_faq2_q:        { tr: 'Online Ableton dersleri nasıl yapılıyor?', en: 'How are online Ableton lessons conducted?' },
    eg_faq2_a:        { tr: 'Dersler Google Meet veya Zoom üzerinden yapılıyor. Ekran paylaşımı ile Ableton projen üzerinde çalışıyoruz; birebir geri bildirim ve anlık düzeltmelerle öğrenme çok daha hızlı gerçekleşiyor.', en: 'Lessons are conducted via Google Meet or Zoom. We work on your Ableton project via screen sharing; learning happens much faster with one-on-one feedback and instant corrections.' },
    eg_faq3_q:        { tr: 'Prodüksiyon öğrenmek için ne kadar süre gerekiyor?', en: 'How long does it take to learn production?' },
    eg_faq3_a:        { tr: 'Seviyeye ve haftalık pratik süresine bağlı olarak değişir. Sıfırdan başlayan bir öğrenci 3-6 ay içinde kendi parçalarını üretebilir hale geliyor.', en: 'It varies depending on level and weekly practice time. A student starting from zero can produce their own tracks within 3-6 months.' },
    eg_faq4_q:        { tr: 'Hangi elektronik müzik türlerini öğretiyorsunuz?', en: 'Which electronic music genres do you teach?' },
    eg_faq4_a:        { tr: 'Melodic Techno, Techno, Dark Minimal, Minimal Tech, Minimal Bass ve Indie Dance dahil pek çok elektronik türde eğitim veriyorum.', en: 'I teach many electronic genres including Melodic Techno, Techno, Dark Minimal, Minimal Tech, Minimal Bass and Indie Dance.' },
    eg_magazine_title: { tr: '// Prodüksiyon Dergisi',         en: '// Production Magazine' },
    eg_magazine_label: { tr: 'PRODÜKSIYON DERGİSİ',           en: 'PRODUCTION MAGAZINE' },
    eg_magazine_pages: { tr: '35 SAYFA',                       en: '35 PAGES' },
    eg_magazine_h:    { tr: 'Elektronik Müzik Prodüksiyonu',   en: 'Electronic Music Production' },
    eg_magazine_sub:  { tr: 'Başlangıç Rehberi',               en: "Beginner's Guide" },
    eg_magazine_desc: { tr: "Berkay Er tarafından hazırlanan bu dergide prodüksiyon temelleri, Ableton workflow'u, ses tasarımı ve melodic techno yapım teknikleri yer alıyor.", en: "This magazine prepared by Berkay Er covers production fundamentals, Ableton workflow, sound design and melodic techno production techniques." },
